'use client';

import { useEffect } from 'react';
import Link from 'next/link';

export default function DashboardError({ error, unstable_retry }) {
  useEffect(() => {
    console.error(error);
  }, [error]);

  return (
    <div className="min-h-[60vh] flex flex-col items-center justify-center px-6 text-center">
      <div className="w-16 h-16 bg-red-50 rounded-2xl flex items-center justify-center mb-6">
        <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#ef4444" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
      </div>
      <h2 className="text-2xl font-black text-slate-900 mb-3 tracking-tight">Something went wrong</h2>
      <p className="text-slate-500 mb-8 max-w-sm font-medium">
        We couldn't load this section of your dashboard. Please try again.
      </p>
      <div className="flex gap-3">
        <button
          onClick={unstable_retry}
          className="bg-primary text-white px-6 py-3 rounded-full font-bold text-sm hover:bg-primary/90 transition-all active:scale-95"
        >
          Try Again
        </button>
        <Link
          href="/account"
          className="bg-slate-100 text-slate-700 px-6 py-3 rounded-full font-bold text-sm hover:bg-slate-200 transition-all"
        >
          Dashboard Home
        </Link>
      </div>
    </div>
  );
}

import BlogCard from '@/components/blog/BlogCard';
import Link from 'next/link';
import { listBlogs } from '@/services/blogService';

const PAGE_SIZE = 9;

const BLOG_CATEGORIES = [
  { label: 'All', value: '' },
  { label: 'Market Trends', value: 'market_trends' },
  { label: 'Buying Guide', value: 'buying_guide' },
  { label: 'Legal', value: 'legal' },
  { label: 'Investment', value: 'investment' },
  { label: 'Lifestyle', value: 'lifestyle' },
];

const getCurrentPage = (rawPage) => {
  const page = Number(rawPage);
  if (!Number.isFinite(page) || page < 1) return 1;
  return Math.floor(page);
};

const getSearchText = (value) => {
  if (typeof value !== 'string') return '';
  return value.trim().slice(0, 100);
};

const isValidCategory = (value) =>
  BLOG_CATEGORIES.some((item) => item.value === value);

export default async function BlogsPage({ searchParams }) {
  const params = await searchParams;
  const currentPage = getCurrentPage(params?.page);
  const currentCategory = isValidCategory(params?.category || '')
    ? (params?.category || '')
    : '';
  const currentSearch = getSearchText(params?.search);

  let posts = [];
  let meta = null;
  try {
    const response = await listBlogs({
      page: currentPage,
      limit: PAGE_SIZE,
      category: currentCategory || undefined,
      search: currentSearch || undefined,
    });
    posts = response.items || [];
    meta = response.meta || null;
  } catch {
    posts = [];
    meta = null;
  }

  const featured = currentPage === 1 ? posts[0] || null : null;
  const regularPosts = featured ? posts.slice(1) : posts;

  const totalPages = Math.max(1, Number(meta?.totalPages || 1));
  const prevPage = currentPage > 1 ? currentPage - 1 : null;
  const nextPage = currentPage < totalPages ? currentPage + 1 : null;

  const visiblePages = [];
  const startPage = Math.max(1, currentPage - 1);
  const endPage = Math.min(totalPages, currentPage + 1);
  for (let page = startPage; page <= endPage; page += 1) {
    visiblePages.push(page);
  }

  const buildBlogsHref = (
    page,
    {
      category = currentCategory,
      search = currentSearch,
    } = {}
  ) => {
    const qs = new URLSearchParams();
    if (page > 1) qs.set('page', String(page));
    if (category) qs.set('category', category);
    if (search) qs.set('search', search);
    const query = qs.toString();
    return query ? `/blogs?${query}` : '/blogs';
  };

  const popularSeries = [
    { label: 'Market Trends', value: 'market_trends', count: 24 },
    { label: 'Investment', value: 'investment', count: 18 },
    { label: 'Legal', value: 'legal', count: 12 },
    { label: 'Buying Guide', value: 'buying_guide', count: 45 },
  ];

  return (
    <div className="w-full h-full pt-12 pb-24">
      <main className="max-w-screen-2xl mx-auto px-8">
        {/* 📖 Editorial Hero */}
        <section className="mb-20 pt-12">
          <div className="max-w-3xl">
            <h1 className="text-6xl md:text-8xl font-black tracking-tighter text-slate-900 mb-8 leading-none">
              Real Estate <br /> <span className="text-primary italic">Insights</span> & Blogs
            </h1>
            <p className="text-xl text-slate-500 leading-relaxed font-medium opacity-80 max-w-2xl">
              Expert advice, market trends, and neighbourhood guides for Mumbai's discerning property seekers. Curated by the city's leading architectural and market analysts.
            </p>
          </div>
        </section>

        {/* 🔍 Category & Search Console */}
        <section className="mb-16 flex flex-col lg:flex-row lg:items-center justify-between gap-10">
          <div className="flex flex-wrap gap-3">
            {BLOG_CATEGORIES.map((cat) => (
              <Link
                key={cat.label}
                href={buildBlogsHref(1, { category: cat.value })}
                className={`px-8 py-3.5 rounded-full text-sm font-black tracking-tight transition-all ${currentCategory === cat.value ? 'bg-primary text-white shadow-xl shadow-primary/20' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}
              >
                {cat.label}
              </Link>
            ))}
          </div>
          <form action="/blogs" method="GET" className="relative w-full lg:max-w-md group flex items-center">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary transition-colors"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            {currentCategory ? <input type="hidden" name="category" value={currentCategory} /> : null}
            <input
              className="w-full pl-16 pr-28 py-5 bg-white border-none rounded-full shadow-2xl shadow-slate-200/50 focus:ring-2 focus:ring-primary/20 placeholder:text-slate-400 font-bold transition-all"
              placeholder="Search blogs by keyword"
              type="text"
              name="search"
              defaultValue={currentSearch}
            />
            <button
              type="submit"
              className="absolute right-3 px-5 py-2.5 rounded-full bg-primary text-white text-xs font-black tracking-wide hover:opacity-90 transition-opacity"
            >
              Search
            </button>
          </form>
        </section>

        {(currentSearch || currentCategory) && (
          <section className="mb-12 flex items-center justify-between gap-4">
            <p className="text-sm font-semibold text-slate-500">
              Showing results
              {currentCategory ? ` in ${BLOG_CATEGORIES.find((item) => item.value === currentCategory)?.label || currentCategory}` : ''}
              {currentSearch ? ` for "${currentSearch}"` : ''}.
            </p>
            <Link
              href="/blogs"
              className="text-xs font-black tracking-widest uppercase text-slate-500 hover:text-primary transition-colors"
            >
              Clear all
            </Link>
          </section>
        )}

        {/* ⭐ Featured Insight */}
        {featured && (
          <section className="mb-24">
            <div className="group relative overflow-hidden rounded-[3.5rem] bg-white border border-slate-50 shadow-sm flex flex-col lg:flex-row transition-all hover:shadow-2xl duration-700">
              <div className="lg:w-3/5 h-112.5 lg:h-auto relative overflow-hidden">
                <img 
                  src={featured.image} 
                  alt={featured.title} 
                  className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105"
                />
                <div className="absolute top-8 left-8">
                  <span className="bg-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.2em] text-primary shadow-2xl">
                    {featured.category}
                  </span>
                </div>
              </div>
              <div className="lg:w-2/5 p-16 flex flex-col justify-center bg-slate-50/30">
                <div className="mb-6 flex items-center gap-3 text-slate-400 text-xs font-black uppercase tracking-widest">
                  <span>{featured.date}</span>
                  <span className="w-1.5 h-1.5 bg-primary rounded-full"></span>
                  <span>{featured.readTime}</span>
                </div>
                <h2 className="text-4xl font-black text-slate-900 mb-8 leading-tight tracking-tighter group-hover:text-primary transition-colors">
                  {featured.title}
                </h2>
                <p className="text-slate-500 mb-10 leading-relaxed text-lg font-medium">
                  {featured.excerpt}
                </p>
                <Link 
                  href={`/blogs/${featured.slug}`} 
                  className="w-fit flex items-center gap-3 bg-primary text-white px-10 py-5 rounded-full font-black text-lg hover:gap-5 transition-all shadow-2xl shadow-primary/20"
                >
                  Read Full Insight
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
                </Link>
              </div>
            </div>
          </section>
        )}

        <div className="flex flex-col lg:flex-row gap-20">
          {/* 📰 Insights Feed (Main Grid) */}
          <div className="lg:w-2/3">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              {regularPosts.map((post, i) => (
                <div key={i} className="group">
                  <BlogCard post={post} />
                </div>
              ))}
            </div>

            {posts.length === 0 && (
              <p className="text-sm font-medium text-slate-500">
                No blog posts are published yet. Please check back soon.
              </p>
            )}
            
            {/* Pagination */}
            <div className="mt-20 flex items-center justify-center gap-5">
              {prevPage ? (
                <Link href={buildBlogsHref(prevPage)} className="w-14 h-14 rounded-full flex items-center justify-center text-slate-400 bg-slate-50 hover:bg-slate-100 transition-all font-black">
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                </Link>
              ) : (
                <span className="w-14 h-14 rounded-full flex items-center justify-center text-slate-300 bg-slate-50 cursor-not-allowed">
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                </span>
              )}

              {startPage > 1 && (
                <>
                  <Link href={buildBlogsHref(1)} className="w-14 h-14 rounded-full flex items-center justify-center text-slate-400 bg-slate-50 hover:bg-slate-100 transition-all font-black">1</Link>
                  {startPage > 2 && <span className="text-slate-300 font-black tracking-widest px-2">...</span>}
                </>
              )}

              {visiblePages.map((page) => (
                <Link
                  key={page}
                  href={buildBlogsHref(page)}
                  className={`w-14 h-14 rounded-full flex items-center justify-center font-black transition-all ${page === currentPage ? 'bg-primary text-white shadow-xl shadow-primary/20' : 'text-slate-400 bg-slate-50 hover:bg-slate-100'}`}
                >
                  {page}
                </Link>
              ))}

              {endPage < totalPages && (
                <>
                  {endPage < totalPages - 1 && <span className="text-slate-300 font-black tracking-widest px-2">...</span>}
                  <Link href={buildBlogsHref(totalPages)} className="w-14 h-14 rounded-full flex items-center justify-center text-slate-400 bg-slate-50 hover:bg-slate-100 transition-all font-black">{totalPages}</Link>
                </>
              )}

              {nextPage ? (
                <Link href={buildBlogsHref(nextPage)} className="px-10 h-14 rounded-full flex items-center justify-center gap-3 text-slate-900 bg-white border border-slate-100 font-black tracking-tight hover:shadow-lg transition-all group">
                  Next <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="group-hover:translate-x-1 transition-transform"><path d="m9 18 6-6-6-6"/></svg>
                </Link>
              ) : (
                <span className="px-10 h-14 rounded-full flex items-center justify-center gap-3 text-slate-300 bg-slate-50 border border-slate-100 font-black tracking-tight cursor-not-allowed">
                  Next <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
                </span>
              )}
            </div>
          </div>

          {/* 📎 Sidebar */}
          <aside className="lg:w-1/3">
            <div className="sticky top-32 space-y-12">
              {/* Popular Categories */}
              <div className="bg-slate-50 p-10 rounded-[3rem] border border-slate-100">
                <h4 className="text-2xl font-black text-slate-900 mb-8 tracking-tighter">Popular Series</h4>
                <div className="space-y-6">
                  {popularSeries.map((cat) => (
                    <Link key={cat.value} href={buildBlogsHref(1, { category: cat.value })} className="flex items-center justify-between group">
                      <span className="text-slate-500 font-black text-sm tracking-tight group-hover:text-primary transition-colors">{cat.label}</span>
                      <span className="bg-white w-10 h-10 flex items-center justify-center rounded-full text-xs font-black text-slate-400 group-hover:bg-primary group-hover:text-white transition-all shadow-sm">{cat.count}</span>
                    </Link>
                  ))}
                </div>
              </div>

              {/* Trending Now */}
              <div>
                <h4 className="text-2xl font-black text-slate-900 mb-8 tracking-tighter italic">Trending <span className="text-primary tracking-normal">Now</span></h4>
                <div className="space-y-10">
                  {[
                    { title: "Navigating the Resale Market in South Mumbai", time: "10 min read", img: "https://lh3.googleusercontent.com/aida-public/AB6AXuDrnjcGoKcEUn24VJmBmhIpFaAXEC0YetjJ9SZzLs2gp_mE464NrUBXscX50mymvG6PXL9wO-jEYtzxWFzI8JbdFHq8xJyG1LbOlu5oseUByt4uuI3rnAuCnPRvL54G5pxdafaunXnxjAMIJ8S3IfP7L7IBXdqBcehHR2pd_Iw301FcAd9p8DUoACKUZKvP7bt2s5I4vu7V3qW51vLTvHaacdy_Dq4xGIY8ggzDLDjzHuESn8-gkwp6hH_YExvoTHSZIzGhxCThZCg" },
                    { title: "How Metro Line 3 is Reshaping Property Values", time: "7 min read", img: "https://lh3.googleusercontent.com/aida-public/AB6AXuC_3Lytpw_NSLWittm05OLvrFTV1lkwAnkTXP-iE-hXzqYb9Xvl3YyypuvyQ4GdbOHZx77dZ4Knuhrma8UjIoQ0s7khhGmNkvI2GhB1sIYj6VvOm3NDh__afskWk1J0Knj2hDMEpAI4RXbgBoj7YRZ-9uVZ85Rj3xg7NNIsciCDNmcmI5CsBbsh2xlUM41pWCu4CmEyUWUtrm2-t9WV8KIcdaPZ6GHxsqTn-i12FFTfdlcx93fUVBq8PT1f1JewFTse7XqHkc1c6Yo" }
                  ].map((trend, i) => (
                    <div key={i} className="flex gap-6 group cursor-pointer">
                      <div className="w-24 h-24 shrink-0 rounded-3xl overflow-hidden shadow-lg border-2 border-white group-hover:rotate-3 transition-all duration-500">
                        <img src={trend.img} alt={trend.title} className="w-full h-full object-cover" />
                      </div>
                      <div className="flex flex-col justify-center">
                        <h5 className="font-black text-sm text-slate-900 leading-snug group-hover:text-primary transition-colors line-clamp-2 tracking-tight">{trend.title}</h5>
                        <span className="text-[10px] text-slate-400 uppercase font-black tracking-widest mt-2">{trend.time}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Newsletter */}
              <div className="bg-primary p-12 rounded-[3.5rem] text-white shadow-2xl shadow-primary/40 relative overflow-hidden group">
                <div className="absolute -top-20 -left-20 w-48 h-48 bg-white/10 rounded-full blur-3xl group-hover:bg-white/20 transition-all"></div>
                <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mb-8 opacity-40"><rect width="20" height="16" x="2" y="4" rx="2"/><path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7"/></svg>
                <h4 className="text-3xl font-black mb-4 tracking-tighter leading-none">Subscribe for <br /> Insights</h4>
                <p className="text-white/70 text-sm mb-8 leading-relaxed font-medium">Join 5,000+ investors receiving our weekly analysis.</p>
                <div className="space-y-4">
                  <input 
                    className="w-full px-8 py-5 rounded-full bg-white/10 border-white/20 text-white placeholder:text-white/40 focus:ring-white/40 focus:border-white/40 text-sm font-bold transition-all" 
                    placeholder="Your email address" 
                    type="email"
                  />
                  <button className="w-full py-5 rounded-full bg-white text-primary font-black text-sm hover:scale-[1.03] transition-all shadow-2xl shadow-black/10">Subscribe Now</button>
                </div>
              </div>
            </div>
          </aside>
        </div>
      </main>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import CompareHeader from '@/components/property/compare/CompareHeader';
import CompareGrid from '@/components/property/compare/CompareGrid';
import { getCompareProperties, removeCompareProperty } from '@/services/userService';

export default function ComparePage() {
  const [comparedProperties, setComparedProperties] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getCompareProperties()
      .then(setComparedProperties)
      .catch(() => setComparedProperties([]))
      .finally(() => setLoading(false));
  }, []);

  const handleRemove = async (id) => {
    try {
      await removeCompareProperty(id);
      setComparedProperties((prev) => prev.filter((p) => p.id !== id));
    } catch {
      // Remove locally even if API fails
      setComparedProperties((prev) => prev.filter((p) => p.id !== id));
    }
  };

  return (
    <div className="bg-white min-h-screen">
      <main className="max-w-[1440px] mx-auto px-8 py-12">
        {/* Header Section */}
        <div className="flex items-center gap-6 mb-16">
          <Link 
            href="/buy"
            className="w-14 h-14 rounded-full bg-slate-50 border border-slate-100 flex items-center justify-center text-primary shadow-sm hover:shadow-xl hover:shadow-primary/10 hover:bg-white transition-all active:scale-95 group"
          >
            <svg 
              xmlns="http://www.w3.org/2000/svg" 
              width="24" 
              height="24" 
              viewBox="0 0 24 24" 
              fill="none" 
              stroke="currentColor" 
              strokeWidth="3" 
              strokeLinecap="round" 
              strokeLinejoin="round" 
              className="group-hover:-translate-x-1 transition-transform"
            >
              <path d="m15 18-6-6 6-6"/>
            </svg>
          </Link>
          <div>
            <h1 className="text-5xl font-black tracking-tighter text-slate-900 mb-2">
              Compare Properties
            </h1>
            <p className="text-slate-500 font-medium text-lg">
              Side-by-side analysis of your top editorial picks in Mumbai
            </p>
          </div>
        </div>

        {comparedProperties.length > 0 ? (
          <>
            <CompareHeader 
              properties={comparedProperties} 
              onRemove={handleRemove} 
            />
            <CompareGrid 
              properties={comparedProperties} 
            />
          </>
        ) : (
          <div className="py-32 text-center bg-slate-50 rounded-[3rem] border-2 border-dashed border-slate-200">
            <div className="w-20 h-20 bg-white rounded-3xl shadow-xl flex items-center justify-center text-slate-300 mx-auto mb-8">
              <span className="material-symbols-outlined text-4xl">compare_arrows</span>
            </div>
            <h2 className="text-2xl font-black text-slate-900 mb-4">No Properties Selected</h2>
            <p className="text-slate-500 font-medium mb-12 max-w-sm mx-auto">
              Add properties from the listings page to start a detailed side-by-side comparison.
            </p>
            <Link 
              href="/buy" 
              className="px-10 py-5 bg-primary text-white rounded-full font-black text-xs uppercase tracking-widest shadow-2xl shadow-primary/20 hover:bg-primary/90 transition-all active:scale-95"
            >
              Browse Listings
            </Link>
          </div>
        )}

        {/* Comparison Insight Section */}
        {comparedProperties.length > 0 && (
          <section className="mt-32 p-12 bg-slate-900 rounded-[3rem] text-white relative overflow-hidden">
            <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-primary/10 blur-[100px] rounded-full translate-x-1/2 -translate-y-1/2"></div>
            <div className="relative z-10 grid grid-cols-1 md:grid-cols-2 gap-16 items-center">
              <div>
                <span className="text-primary font-black uppercase tracking-[0.4em] text-xs mb-6 block">Editorial Insight</span>
                <h2 className="text-4xl font-black tracking-tighter leading-tight mb-8">
                  Confused between <br/>your top choices?
                </h2>
                <p className="text-slate-400 text-lg font-medium leading-relaxed mb-10">
                  Our area experts can provide a personalized feasibility report comparing appreciation potential, 
                  infrastructure development, and developer track records for these specific projects.
                </p>
                <button className="px-10 py-5 bg-primary text-white rounded-full font-black text-xs uppercase tracking-widest hover:scale-105 transition-all shadow-2xl shadow-primary/40">
                  Request Expert Consultation
                </button>
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div className="p-8 bg-white/5 border border-white/10 rounded-3xl backdrop-blur-sm">
                  <h4 className="font-black text-primary text-2xl mb-2">98%</h4>
                  <p className="text-xs font-bold uppercase tracking-widest text-slate-500">Data Accuracy</p>
                </div>
                <div className="p-8 bg-white/5 border border-white/10 rounded-3xl backdrop-blur-sm">
                  <h4 className="font-black text-white text-2xl mb-2">Verified</h4>
                  <p className="text-xs font-bold uppercase tracking-widest text-slate-500">RERA Compliance</p>
                </div>
                <div className="p-8 bg-white/5 border border-white/10 rounded-3xl backdrop-blur-sm col-span-2">
                  <p className="text-slate-300 font-medium italic">"The side-by-side comparison saved us weeks of site visits. Precise and visually clear."</p>
                  <p className="mt-4 text-xs font-black uppercase tracking-widest text-primary">— Mumbai Resident</p>
                </div>
              </div>
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { getErrorMessage } from '@/lib/api/errors';
import { toIndianPhoneE164 } from '@/lib/validation/phone';
import { submitContactForm } from '@/services/contactService';

export default function ContactPage() {
  const [form, setForm] = useState({
    name: '',
    phone: '',
    email: '',
    message: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState({ type: '', message: '' });

  const handleChange = (field) => (event) => {
    setForm((prev) => ({ ...prev, [field]: event.target.value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    const phone = toIndianPhoneE164(form.phone);

    if (!phone) {
      setFeedback({
        type: 'error',
        message: 'Please enter a valid Indian mobile number in +91 format.',
      });
      return;
    }

    setIsSubmitting(true);
    setFeedback({ type: '', message: '' });

    try {
      await submitContactForm({
        name: form.name.trim(),
        phone,
        email: form.email.trim() || undefined,
        message: form.message.trim(),
      });

      setFeedback({
        type: 'success',
        message: 'Message sent successfully. We will get back to you shortly.',
      });
      setForm({ name: '', phone: '', email: '', message: '' });
