import Link from 'next/link';
import { notFound } from 'next/navigation';
import PropertyGallery from '@/components/property/details/PropertyGallery';
import PropertyStickyInfo from '@/components/property/details/PropertyStickyInfo';
import PropertyHighlights from '@/components/property/details/PropertyHighlights';
import PropertyAbout from '@/components/property/details/PropertyAbout';
import PropertyAmenities from '@/components/property/details/PropertyAmenities';
import PropertyFloorPlans from '@/components/property/details/PropertyFloorPlans';
import PropertyLeadForm from '@/components/property/details/PropertyLeadForm';
import PropertyBuilderProfile from '@/components/property/details/PropertyBuilderProfile';
import PropertyCard from '@/components/property/PropertyCard';
import {
  getPropertyById,
  getPropertyBySlug,
  listProperties,
} from '@/services/propertyService';

export default async function PropertyDetailPage({ params }) {
  const { id } = await params;

  let property = null;
  try {
    property = await getPropertyBySlug(id);
  } catch {
    property = null;
  }

  if (!property) {
    try {
      property = await getPropertyById(id);
    } catch {
      property = null;
    }
  }

  if (!property) {
    notFound();
  }

  let similarProperties = [];
  try {
    const response = await listProperties({
      category: property?.raw?.category,
      limit: 6,
    });
    similarProperties = (response.items || [])
      .filter((item) => item.id !== property.id)
      .slice(0, 3);
  } catch {
    similarProperties = [];
  }

  const neighborhoodHighlights = property?.neighborhood?.highlights || [];
  const gallery = property?.gallery || [];
  const highlights = property?.highlights || [];
  const amenities = property?.amenities || [];

  return (
    <main className="pt-8 pb-24 max-w-7xl mx-auto px-6 lg:px-8">
      {/* Breadcrumbs */}
      <nav aria-label="Breadcrumb" className="flex text-[10px] font-bold uppercase tracking-[0.2em] text-slate-400 mb-8 px-1">
        <ol className="inline-flex items-center space-x-2">
          <li><Link href="/" className="hover:text-primary transition-colors">Home</Link></li>
          <li className="flex items-center">
            <svg className="w-3 h-3 mx-1 text-slate-300" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
            <Link href="/buy" className="hover:text-primary transition-colors">Listings</Link>
          </li>
          <li className="flex items-center">
            <svg className="w-3 h-3 mx-1 text-slate-300" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
            <span className="text-primary truncate max-w-50">{property.title}</span>
          </li>
        </ol>
      </nav>

      {/* Hero Section */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 mb-20">
        <div className="lg:col-span-8">
          <PropertyGallery images={gallery} />
        </div>
        <div className="lg:col-span-4">
          <PropertyStickyInfo property={property} />
        </div>
      </div>

      {/* Main Content Flow */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-8 space-y-20">
          <PropertyHighlights highlights={highlights} />
          <PropertyAbout description={property.longDescription || property.description} />
          <PropertyAmenities amenities={amenities} />
          <PropertyFloorPlans />
          
          {/* Neighborhood Placeholder */}
          <section>
            <h2 className="text-2xl font-heading font-extrabold mb-8 text-slate-900">Neighborhood & Location</h2>
            <div className="rounded-2xl overflow-hidden shadow-lg h-96 relative mb-8 border border-slate-100">
              <img 
                className="w-full h-full object-cover" 
                src="https://images.unsplash.com/photo-1524813686514-a57563d77965?auto=format&fit=crop&q=80&w=1200" 
                alt="Neighborhood Map Placeholder" 
              />
              <div className="absolute bottom-6 left-6 right-6 bg-white/90 backdrop-blur-md p-6 rounded-xl flex flex-wrap gap-8 border border-white shadow-xl">
                  {neighborhoodHighlights.map((nh, idx) => (
                    <div key={idx} className="flex items-center gap-3">
                      <span className="material-symbols-outlined text-primary">{nh.icon}</span>
                      <div>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400">{nh.label}</p>
                        <p className="font-bold text-slate-700 text-sm">{nh.value}</p>
                      </div>
                    </div>
                 ))}
              </div>
            </div>
          </section>
        </div>

        {/* Right Column Sidebar */}
        <div className="lg:col-span-4 space-y-8">
          <PropertyLeadForm property={property} />
          <PropertyBuilderProfile builder={property.builder} />
        </div>
      </div>

      {/* Similar Properties Carousel (Simplified for now) */}
      <section className="mt-32">
        <div className="flex justify-between items-center mb-10">
          <h2 className="text-3xl font-heading font-extrabold text-slate-900">You May Also Like</h2>
          <div className="flex gap-4">
            <button className="w-12 h-12 rounded-full border-2 border-slate-200 flex items-center justify-center hover:bg-primary hover:text-white hover:border-primary transition-all group">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <button className="w-12 h-12 rounded-full border-2 border-slate-200 flex items-center justify-center hover:bg-primary hover:text-white hover:border-primary transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {similarProperties.map((p) => (
            <PropertyCard key={p.id} property={p} />
          ))}
        </div>

        {similarProperties.length === 0 && (
          <p className="mt-6 text-sm font-medium text-slate-500">
            More similar listings will appear here soon.
          </p>
        )}
      </section>
    </main>
  );
}

import PropertyCard from '@/components/property/PropertyCard';
import PropertyFilters from '@/components/property/PropertyFilters';
import PropertyGrid from '@/components/property/PropertyGrid';
import PropertySortBar from '@/components/property/PropertySortBar';
import Link from 'next/link';
import { listProperties } from '@/services/propertyService';

const PAGE_SIZE = 12;
const BASE_PATH = '/rent';
const ALLOWED_SORT = new Set(['newest', 'price_asc', 'price_desc']);
const ALLOWED_FURNISHING = new Set(['unfurnished', 'semi_furnished', 'furnished']);

const getCurrentPage = (rawPage) => {
  const page = Number(rawPage);
  if (!Number.isFinite(page) || page < 1) return 1;
  return Math.floor(page);
};

const normalizeText = (value) => {
  if (typeof value !== 'string') return '';
  return value.trim();
};

const normalizeNumberString = (value) => {
  if (value === undefined || value === null || value === '') return '';
  const number = Number(value);
  if (!Number.isFinite(number) || number < 0) return '';
  return String(Math.floor(number));
};

const normalizeBhk = (value) => {
  const numeric = normalizeNumberString(value);
  if (!numeric) return '';
  const bhk = Number(numeric);
  if (bhk < 1 || bhk > 10) return '';
  return String(bhk);
};

const normalizeSort = (value) => {
  if (!ALLOWED_SORT.has(value)) return 'newest';
  return value;
};

const normalizeFurnishing = (value) => {
  if (!ALLOWED_FURNISHING.has(value)) return '';
  return value;
};

const buildListingHref = (basePath, query, page) => {
  const params = new URLSearchParams();
  if (query.area) params.set('area', query.area);
  if (query.minPrice) params.set('minPrice', query.minPrice);
  if (query.maxPrice) params.set('maxPrice', query.maxPrice);
  if (query.bhk) params.set('bhk', query.bhk);
  if (query.furnishing) params.set('furnishing', query.furnishing);
  if (query.sortBy && query.sortBy !== 'newest') params.set('sortBy', query.sortBy);
  if (page > 1) params.set('page', String(page));

  const queryString = params.toString();
  return queryString ? `${basePath}?${queryString}` : basePath;
};

export default async function PropertiesPage({ searchParams }) {
  const params = await searchParams;
  const currentPage = getCurrentPage(params?.page);
  const currentQuery = {
    area: normalizeText(params?.area),
    minPrice: normalizeNumberString(params?.minPrice),
    maxPrice: normalizeNumberString(params?.maxPrice),
    bhk: normalizeBhk(params?.bhk),
    furnishing: normalizeFurnishing(params?.furnishing),
    sortBy: normalizeSort(params?.sortBy),
  };

  let properties = [];
  let meta = null;
  try {
    const response = await listProperties({
      category: 'rent',
      limit: PAGE_SIZE,
      page: currentPage,
      sortBy: currentQuery.sortBy,
      ...(currentQuery.area ? { area: currentQuery.area } : {}),
      ...(currentQuery.minPrice ? { minPrice: currentQuery.minPrice } : {}),
      ...(currentQuery.maxPrice ? { maxPrice: currentQuery.maxPrice } : {}),
      ...(currentQuery.bhk ? { bhk: currentQuery.bhk } : {}),
      ...(currentQuery.furnishing ? { furnishing: currentQuery.furnishing } : {}),
    });
    properties = response.items || [];
    meta = response.meta || null;
  } catch {
    properties = [];
    meta = null;
  }

  const totalPages = Math.max(1, Number(meta?.totalPages || 1));
  const prevPage = currentPage > 1 ? currentPage - 1 : null;
  const nextPage = currentPage < totalPages ? currentPage + 1 : null;

  const visiblePages = [];
  const startPage = Math.max(1, currentPage - 1);
  const endPage = Math.min(totalPages, currentPage + 1);
  for (let page = startPage; page <= endPage; page += 1) {
    visiblePages.push(page);
  }

  return (
    <main className="max-w-7xl mx-auto px-6 py-12 lg:px-8">
      {/* Breadcrumbs & Header */}
      <header className="mb-12">
        <nav aria-label="Breadcrumb" className="flex text-[10px] font-bold uppercase tracking-[0.2em] text-slate-400 mb-4">
          <ol className="inline-flex items-center space-x-2">
            <li><Link href="/" className="hover:text-primary transition-colors text-[10px]">Home</Link></li>
            <li className="flex items-center">
              <svg className="w-3 h-3 mx-1 text-slate-300" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
              <span className="text-primary">Properties for Rent</span>
            </li>
          </ol>
        </nav>
        <h1 className="text-5xl font-extrabold tracking-tighter text-slate-900 mb-4">
          Mumbai Rental Properties
        </h1>
        <p className="text-slate-500 text-lg max-w-2xl leading-relaxed">
          Discover curated luxury residences across South Mumbai, Bandra, and beyond. 
          Refined living in India's most vibrant skyline.
        </p>
      </header>

      <div className="flex flex-col lg:flex-row gap-12">
        {/* Sidebar Filters */}
        <PropertyFilters basePath={BASE_PATH} currentQuery={currentQuery} />

        {/* Main Content */}
        <div className="grow">
          <PropertySortBar basePath={BASE_PATH} currentQuery={currentQuery} />
          
          <PropertyGrid columns={2}>
            {properties.map((property) => (
              <PropertyCard key={property.id} property={property} />
            ))}
          </PropertyGrid>

          {properties.length === 0 && (
            <p className="mt-8 text-sm font-medium text-slate-500">
              No rental listings are available right now. Please check back shortly.
            </p>
          )}

          {/* Pagination */}
          <div className="mt-20 flex justify-center items-center gap-2">
            {prevPage ? (
              <Link href={buildListingHref(BASE_PATH, currentQuery, prevPage)} className="w-10 h-10 rounded-full flex items-center justify-center text-slate-400 hover:bg-slate-100 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
              </Link>
            ) : (
              <span className="w-10 h-10 rounded-full flex items-center justify-center text-slate-300 cursor-not-allowed">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
              </span>
            )}

            {startPage > 1 && (
              <>
                <Link href={buildListingHref(BASE_PATH, currentQuery, 1)} className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-slate-100 font-bold text-slate-600 transition-colors">1</Link>
                {startPage > 2 && <span className="px-2 text-slate-300">...</span>}
              </>
            )}

            {visiblePages.map((page) => (
              <Link
                key={page}
                href={buildListingHref(BASE_PATH, currentQuery, page)}
                className={`w-10 h-10 rounded-full flex items-center justify-center font-bold transition-colors ${page === currentPage ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'hover:bg-slate-100 text-slate-600'}`}
              >
                {page}
              </Link>
            ))}

            {endPage < totalPages && (
              <>
                {endPage < totalPages - 1 && <span className="px-2 text-slate-300">...</span>}
                <Link href={buildListingHref(BASE_PATH, currentQuery, totalPages)} className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-slate-100 font-bold text-slate-600 transition-colors">{totalPages}</Link>
              </>
            )}

            {nextPage ? (
              <Link href={buildListingHref(BASE_PATH, currentQuery, nextPage)} className="w-10 h-10 rounded-full flex items-center justify-center text-primary hover:bg-slate-100 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
              </Link>
            ) : (
              <span className="w-10 h-10 rounded-full flex items-center justify-center text-slate-300 cursor-not-allowed">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Floating Contact CTA */}
      <button className="fixed bottom-8 right-8 z-60 bg-primary text-white flex items-center gap-3 px-8 py-4 rounded-full shadow-2xl hover:scale-105 transition-all font-bold active:scale-95 group">
        <svg className="group-hover:rotate-12 transition-transform" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
        Contact Expert
      </button>
    </main>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { listBanners } from '@/services/bannerService';
import BannerSlotCard from '@/components/admin/banners/BannerSlotCard';

export default function BannerManagementPage() {
  const [banners, setBanners] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchBanners();
  }, []);

  const fetchBanners = async () => {
    setLoading(true);
    try {
      const data = await listBanners();
      setBanners(data);
    } catch (error) {
      console.error('Failed to fetch banners:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleReplace = (id) => {
    // In a real app, this would trigger a file upload modal
    alert(`Asset update requested for slot ID: ${id}. Initializing secure upload tunnel...`);
  };

  return (
    <div className="max-w-7xl mx-auto">
      {/* Header Section */}
      <div className="mb-16">
        <h1 className="text-5xl font-black tracking-tighter text-slate-900 lg:text-7xl">
          Visual <span className="text-primary italic">Identity</span>
        </h1>
        <p className="text-slate-500 font-medium text-xl mt-6 max-w-2xl leading-relaxed">
          Manage and optimize the high-impact visual banners on your platform's main entrance. Every pixel defines the "Bricks" experience.
        </p>
      </div>

      {loading ? (
        <div className="py-32 flex flex-col items-center justify-center text-slate-300">
          <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin mb-6"></div>
          <span className="text-[10px] font-black uppercase tracking-widest">Rendering Assets...</span>
        </div>
      ) : (
        <div className="space-y-12">
          {banners.map((banner) => (
            <BannerSlotCard 
              key={banner.id} 
              banner={banner} 
              onReplace={handleReplace} 
            />
          ))}
        </div>
      )}

      {/* Strategic Optimization Widgets (Bento Grid Style) */}
      <div className="mt-20 grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-slate-900 p-12 rounded-[3.5rem] text-white relative overflow-hidden group">
          <div className="absolute top-0 right-0 w-48 h-48 bg-primary opacity-10 blur-[80px] rounded-full translate-x-1/2 -translate-y-1/2 group-hover:opacity-20 transition-all duration-700"></div>
          <div className="flex items-start gap-8 relative z-10">
            <div className="bg-white/10 p-4 rounded-3xl backdrop-blur-md text-primary">
              <span className="material-symbols-outlined text-3xl font-black">auto_awesome</span>
            </div>
            <div>
              <h4 className="text-2xl font-black tracking-tight mb-4">Responsive Orchestration</h4>
              <p className="text-slate-400 font-medium leading-[1.8] text-lg">
                Our platform automatically generates optimized responsive variants of your banners for mobile, tablet, and retina-desktop viewports.
              </p>
            </div>
          </div>
        </div>

        <div className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-2xl shadow-slate-200/50 flex items-start gap-8 group">
          <div className="bg-primary/10 p-4 rounded-3xl text-primary group-hover:scale-110 transition-transform">
            <span className="material-symbols-outlined text-3xl font-black">analytics</span>
          </div>
          <div>
            <h4 className="text-2xl font-black tracking-tight mb-4 text-slate-900">Engagement Intelligence</h4>
            <p className="text-slate-500 font-medium leading-[1.8] text-lg">
              Click-through rates (CTR) and interaction heatmaps are tracked for every banner slot to help you optimize visual performance.
            </p>
          </div>
        </div>
      </div>

      {/* Footer Branding */}
      <footer className="mt-32 py-12 text-center border-t border-slate-50">
        <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-300">
           © 2026 BRICKS ADMINISTRATIVE CONSOLE • Visual Engine v4.0
        </p>
      </footer>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { listProperties, deleteProperty, getPropertyById } from '@/services/propertyService';

const CATEGORY_LABEL = { buy: 'Buy', rent: 'Rent', commercial: 'Commercial', new_launch: 'New Launch' };

function formatPrice(price) {
  if (!price) return '—';
  if (price >= 10000000) return `${(price / 10000000).toFixed(2)} Cr`;
  if (price >= 100000) return `${(price / 100000).toFixed(2)} L`;
  return price.toLocaleString('en-IN');
}

function hasValue(value) {
  if (value === null || value === undefined) return false;
  if (typeof value === 'string') return value.trim().length > 0;
  if (Array.isArray(value)) return value.length > 0;
  return true;
}

export default function PropertyManagementPage() {
  const [properties, setProperties] = useState([]);
  const [meta, setMeta] = useState(null);
  const [loading, setLoading] = useState(true);
  const [category, setCategory] = useState('');
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [deletingId, setDeletingId] = useState(null);
  const [openActionFor, setOpenActionFor] = useState(null);
  const [viewingProperty, setViewingProperty] = useState(null);
  const [loadingPropertyDetail, setLoadingPropertyDetail] = useState(false);

  const fetchProperties = useCallback(async () => {
    setLoading(true);
    try {
      const query = { page, limit: 12 };
      if (category) query.category = category;
      if (search) query.search = search;
      const res = await listProperties(query, { map: false });
      setProperties(res.items || []);
      setMeta(res.meta || null);
    } catch {
      setProperties([]);
    } finally {
      setLoading(false);
    }
  }, [category, search, page]);

  useEffect(() => { fetchProperties(); }, [fetchProperties]);

  const handleDelete = async (id, title) => {
    setOpenActionFor(null);
    if (!confirm(`Delete "${title}"? This cannot be undone.`)) return;
    setDeletingId(id);
    try {
      await deleteProperty(id);
      setProperties((prev) => prev.filter((p) => p._id !== id));
    } catch {
      alert('Failed to delete property.');
    } finally {
      setDeletingId(null);
    }
  };

  const handleViewProperty = async (id) => {
    setOpenActionFor(null);
    setLoadingPropertyDetail(true);
    try {
      const property = await getPropertyById(id, { map: false });
      setViewingProperty(property);
    } catch {
      alert('Failed to fetch property details.');
    } finally {
      setLoadingPropertyDetail(false);
    }
  };

  return (
    <div className="space-y-10 pb-20">
      {/* Page Header */}
      <div className="flex flex-col md:flex-row justify-between items-end gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tighter">Properties</h1>
          <p className="text-slate-500 font-bold mt-2">Manage your active real estate listings and portfolio.</p>
        </div>
        {meta && (
          <span className="bg-slate-50 border border-slate-100 text-slate-600 px-6 py-3 rounded-2xl text-sm font-black">
            {meta.total} total listings
          </span>
        )}
      </div>

      {/* Filters */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-50 flex flex-wrap gap-6 items-end">
        <div className="flex-1 min-w-55">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Search</label>
          <div className="relative">
            <span className="material-symbols-outlined absolute left-5 top-1/2 -translate-y-1/2 text-slate-400">search</span>
            <input
              className="w-full bg-slate-50 rounded-2xl py-4 pl-14 pr-6 text-sm font-bold outline-none focus:ring-2 focus:ring-primary/20"
              placeholder="Title, area…"
              value={search}
              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
            />
          </div>
        </div>
        <div className="w-48">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Category</label>
          <select
            className="w-full appearance-none bg-slate-50 rounded-2xl px-5 py-4 text-sm font-bold outline-none focus:ring-2 focus:ring-primary/20"
            value={category}
            onChange={(e) => { setCategory(e.target.value); setPage(1); }}
          >
            <option value="">All Types</option>
            <option value="buy">Buy</option>
            <option value="rent">Rent</option>
            <option value="commercial">Commercial</option>
            <option value="new_launch">New Launch</option>
          </select>
        </div>
      </div>

      {/* Properties Table */}
      <div className="bg-white rounded-[3rem] shadow-sm border border-slate-50 overflow-hidden">
        {loading ? (
          <div className="p-10 space-y-4 animate-pulse">
            {[1, 2, 3, 4].map((i) => <div key={i} className="h-20 bg-slate-100 rounded-2xl" />)}
          </div>
        ) : properties.length === 0 ? (
          <div className="py-20 text-center">
            <span className="material-symbols-outlined text-5xl text-slate-200 mb-4 block">home_work</span>
            <p className="text-slate-400 font-bold">No properties found.</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-separate border-spacing-y-2 p-6">
              <thead>
                <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
                  <th className="px-6 py-5">Property</th>
                  <th className="px-6 py-5">Category</th>
                  <th className="px-6 py-5">Location</th>
                  <th className="px-6 py-5">BHK</th>
                  <th className="px-6 py-5">Price</th>
                  <th className="px-6 py-5">Status</th>
                  <th className="px-6 py-5 text-right">Actions</th>
                </tr>
              </thead>
              <tbody>
                {properties.map((prop) => {
                  const heroUrl = prop.heroImage?.url || null;
                  return (
                    <tr key={prop._id} className="bg-slate-50/50 hover:bg-white hover:shadow-xl transition-all group rounded-3xl">
                      <td className="px-6 py-5 rounded-l-3xl">
                        <div className="flex items-center gap-4">
                          <div className="w-14 h-14 rounded-2xl overflow-hidden bg-slate-100 shrink-0 flex items-center justify-center">
                            {heroUrl
                              ? <img src={heroUrl} alt={prop.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                              : <span className="material-symbols-outlined text-slate-300 text-2xl">image</span>
                            }
                          </div>
                          <div>
                            <p className="text-sm font-black text-slate-900 group-hover:text-primary transition-colors">{prop.title}</p>
                            {prop.reraNumber && <p className="text-[10px] text-slate-400 font-medium">RERA: {prop.reraNumber}</p>}
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <span className="text-[10px] font-black uppercase tracking-widest px-3 py-1.5 bg-slate-100 text-slate-600 rounded-full">
                          {CATEGORY_LABEL[prop.category] || prop.category}
                        </span>
                      </td>
                      <td className="px-6 py-5 text-sm font-bold text-slate-600">{prop.location?.area || '—'}</td>
                      <td className="px-6 py-5 text-sm font-bold text-slate-600">{prop.bhk ? `${prop.bhk} BHK` : 'N/A'}</td>
                      <td className="px-6 py-5 text-sm font-black text-primary">₹{formatPrice(prop.price)}</td>
                      <td className="px-6 py-5">
                        <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${prop.isActive !== false ? 'bg-emerald-50 text-emerald-700' : 'bg-slate-100 text-slate-400'}`}>
                          {prop.isActive !== false ? 'Active' : 'Inactive'}
                        </span>
                      </td>
                      <td className="px-6 py-5 text-right rounded-r-3xl">
                        <div className="flex justify-end">
                          <div className="relative">
                            <button
                              type="button"
                              onClick={() => setOpenActionFor((prev) => (prev === prop._id ? null : prop._id))}
                              className="w-9 h-9 flex items-center justify-center rounded-xl border border-slate-100 text-slate-400 hover:text-primary hover:bg-primary/5 transition-all"
                              title="More"
                            >
                              <span className="material-symbols-outlined text-lg">more_horiz</span>
                            </button>

                            {openActionFor === prop._id && (
                              <div className="absolute right-0 top-11 z-20 w-48 rounded-2xl border border-slate-100 bg-white p-2 shadow-2xl shadow-slate-200/60">
                                <button
                                  type="button"
                                  onClick={() => handleViewProperty(prop._id)}
                                  className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-all"
                                >
                                  <span className="material-symbols-outlined text-lg text-primary">visibility</span>
                                  <span>View</span>
                                </button>
                                <Link
                                  href={`/property/${prop.slug || prop._id}`}
                                  target="_blank"
                                  className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-all"
                                >
                                  <span className="material-symbols-outlined text-lg text-primary">open_in_new</span>
                                  <span>Open Public</span>
                                </Link>
                                <button
                                  type="button"
                                  onClick={() => handleDelete(prop._id, prop.title)}
                                  disabled={deletingId === prop._id}
                                  className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-bold text-slate-600 hover:bg-red-50 hover:text-red-600 transition-all disabled:opacity-40"
                                >
                                  <span className="material-symbols-outlined text-lg">delete</span>
                                  <span>{deletingId === prop._id ? 'Deleting…' : 'Delete'}</span>
                                </button>
                              </div>
                            )}
                          </div>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination */}
      {meta && meta.totalPages > 1 && (
        <div className="flex justify-center gap-2">
          {Array.from({ length: meta.totalPages }, (_, i) => i + 1).map((p) => (
            <button
              key={p}
              onClick={() => setPage(p)}
              className={`w-10 h-10 rounded-xl font-black text-sm transition-all ${p === page ? 'bg-primary text-white shadow-lg' : 'bg-white border border-slate-100 text-slate-500 hover:border-primary hover:text-primary'}`}
            >
              {p}
            </button>
          ))}
        </div>
      )}

      {(loadingPropertyDetail || viewingProperty) && (
        <div className="fixed inset-0 z-70 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="w-full max-w-3xl bg-white rounded-4xl border border-slate-100 shadow-2xl overflow-hidden">
            <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Property Details</h3>
              <button
                type="button"
                onClick={() => { setViewingProperty(null); setLoadingPropertyDetail(false); }}
                className="w-10 h-10 rounded-xl bg-slate-50 text-slate-500 hover:text-slate-900 transition-colors"
              >
                <span className="material-symbols-outlined">close</span>
              </button>
            </div>
            <div className="p-8 max-h-[75vh] overflow-y-auto">
              {loadingPropertyDetail ? (
                <div className="space-y-4 animate-pulse">
                  {[1, 2, 3, 4].map((i) => <div key={i} className="h-12 bg-slate-100 rounded-xl" />)}
                </div>
              ) : viewingProperty ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  {[
                    { label: 'Title', value: viewingProperty.title, full: true },
                    { label: 'Category', value: CATEGORY_LABEL[viewingProperty.category] || viewingProperty.category },
                    { label: 'Price', value: hasValue(viewingProperty.price) ? `₹${formatPrice(viewingProperty.price)}` : null },
                    { label: 'BHK', value: viewingProperty.bhk },
                    { label: 'Bathrooms', value: viewingProperty.bathrooms },
                    { label: 'Area (sq.ft)', value: viewingProperty.areaSqft },
                    { label: 'Furnishing', value: viewingProperty.furnishing },
                    { label: 'RERA Number', value: viewingProperty.reraNumber },
                    { label: 'Location Area', value: viewingProperty.location?.area },
                    { label: 'City', value: viewingProperty.location?.city },
                    { label: 'Address', value: viewingProperty.location?.address, full: true },
                    { label: 'Description', value: viewingProperty.description, full: true },
                    {
                      label: 'Amenities',
                      value: Array.isArray(viewingProperty.amenities) ? viewingProperty.amenities.join(', ') : null,
                      full: true,
                    },
                  ]
                    .filter((field) => hasValue(field.value))
                    .map((field) => (
                      <Info key={field.label} label={field.label} value={field.value} full={field.full} />
                    ))}
                </div>
              ) : null}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function Info({ label, value, full = false }) {
  return (
    <div className={`${full ? 'md:col-span-2' : ''} rounded-xl border border-slate-100 bg-slate-50 p-4`}>
      <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-2">{label}</p>
      <p className="text-sm font-bold text-slate-800 wrap-break-word">{String(value)}</p>
    </div>
  );
}

